"use client";

import { useState, useEffect } from "react";
import api from "@/lib/api";

interface Item {
  id: number;
  name: string;
  completed: boolean;
}

export default function ItemList() {
  const [items, setItems] = useState<Item[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  // Fetch items when the component first appears on screen
  useEffect(() => {
    async function fetchItems() {
      try {
        const response = await api.get("/items");
        setItems(response.data);
      } catch (err) {
        setError("Failed to load items from the backend.");
      } finally {
        setLoading(false);
      }
    }
    fetchItems();
  }, []);

  // Function to add a new item
  async function addItem(name: string) {
    try {
      const response = await api.post("/items", { name });
      setItems([...items, response.data]);
    } catch (err) {
      setError("Failed to add item.");
    }
  }

  // Function to delete an item
  async function deleteItem(id: number) {
    try {
      await api.delete(`/items/${id}`);
      setItems(items.filter((item) => item.id !== id));
    } catch (err) {
      setError("Failed to delete item.");
    }
  }

  if (loading) return <p>Loading...</p>;
  if (error) return <p style={{ color: "red" }}>{error}</p>;

  return (
    <div>
      <h2>My Items</h2>
      <ul>
        {items.map((item) => (
          <li key={item.id}>
            {item.name}
            <button onClick={() => deleteItem(item.id)}>Delete</button>
          </li>
        ))}
      </ul>
      <button onClick={() => addItem("New item")}>Add Item</button>
    </div>
  );
}

from flask import jsonify

def register_error_handlers(app):
    """Register error handlers with the Flask app."""

    @app.errorhandler(400)
    def bad_request(error):
        return jsonify({
            "error": "Bad Request",
            "message": "The server could not understand your request. Check that you are sending valid JSON data."
        }), 400

    @app.errorhandler(401)
    def unauthorized(error):
        return jsonify({
            "error": "Unauthorized",
            "message": "You need to log in to access this resource."
        }), 401

    @app.errorhandler(404)
    def not_found(error):
        return jsonify({
            "error": "Not Found",
            "message": "The resource you are looking for does not exist."
        }), 404

    @app.errorhandler(500)
    def server_error(error):
        return jsonify({
            "error": "Internal Server Error",
            "message": "Something went wrong on our end. Please try again later."
        }), 500

